import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext.jsx';
import { toast } from 'react-toastify';


const ROLES = [
  { value: "Admin", label: "Admin", icon: "🛡️", desc: "Full system access" },
  { value: "Manager", label: "Manager", icon: "📋", desc: "Manage orders & staff" },
  { value: "User", label: "Employee", icon: "👤", desc: "Basic access" },
];

const LoginPage = () => {
  const [selectedRole, setSelectedRole] = useState(null);
  const [form, setForm] = useState({ username: "", password: "" });
  const [error, setError] = useState("");
  const [loading, setLoading] = useState(false);
  const [loggedInUser, setLoggedInUser] = useState(null);

  const handleChange = (e) => {
    setForm({ ...form, [e.target.name]: e.target.value });
    setError("");
  };

  const handleRoleSelect = (role) => {
    setSelectedRole(role);
    setError("");
    setForm({ username: "", password: "" });
  };

  const handleLogin = async (e) => {
    e.preventDefault();
    if (!selectedRole) { setError("Please select a role first."); return; }
    setLoading(true);
    setError("");

    try {
      // Replace this block with your real API call:
      // const res = await fetch("https://your-api.com/login", {
      //   method: "POST",
      //   headers: { "Content-Type": "application/json" },
      //   body: JSON.stringify({ username: form.username, password: form.password, role: selectedRole.value }),
      // });
      // const data = await res.json();
      // if (!res.ok) throw new Error(data.message || "Login failed");
      // setLoggedInUser(data.user);

      // Demo simulation:
      await new Promise((r) => setTimeout(r, 1000));
      if (form.username && form.password) {
        setLoggedInUser({ username: form.username, full_name: form.username, role: selectedRole.value });
      } else {
        throw new Error("Invalid username or password.");
      }
    } catch (err) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  };

  const handleLogout = () => {
    setLoggedInUser(null);
    setSelectedRole(null);
    setForm({ username: "", password: "" });
  };

  // ── Success screen ──────────────────────────────────────────────────────────
  if (loggedInUser) {
    const roleInfo = ROLES.find((r) => r.value === loggedInUser.role);
    return (
      <div style={s.wrapper}>
        <div style={s.card}>
          <div style={s.successIcon}>{roleInfo?.icon}</div>
          <h2 style={s.welcomeTitle}>Welcome back!</h2>
          <p style={s.welcomeName}>{loggedInUser.full_name}</p>
          <span style={s.roleBadge}>{loggedInUser.role}</span>
          <button style={s.logoutBtn} onClick={handleLogout}>Log out</button>
        </div>
      </div>
    );
  }
  // ── Login screen ────────────────────────────────────────────────────────────
  return (
    <div style={s.wrapper}>
      <div style={s.card}>

        {/* Brand */}
        <div style={s.brand}>
          <div style={s.brandIcon}>S</div>
          <span style={s.brandName}>Stockist</span>
        </div>

        <h1 style={s.title}>Sign in</h1>
        <p style={s.subtitle}>Select your role to continue</p>

        {/* Role selector */}
        <div style={s.roleGrid}>
          {ROLES.map((role) => {
            const active = selectedRole?.value === role.value;
            return (
              <button
                key={role.value}
                type="button"
                onClick={() => handleRoleSelect(role)}
                style={{
                  ...s.roleCard,
                  ...(active ? s.roleCardActive : {}),
                }}
              >
                <span style={s.roleIcon}>{role.icon}</span>
                <span style={{ ...s.roleLabel, color: active ? "#a5b4fc" : "#fff" }}>
                  {role.label}
                </span>
                <span style={s.roleDesc}>{role.desc}</span>
                {active && <div style={s.roleCheck}>✓</div>}
              </button>
            );
          })}
        </div>

        {/* Credentials form — shown after role is picked */}
        <div style={{
          ...s.formWrap,
          maxHeight: selectedRole ? "400px" : "0px",
          opacity: selectedRole ? 1 : 0,
          overflow: "hidden",
          transition: "max-height 0.4s ease, opacity 0.3s ease",
        }}>
          <form onSubmit={handleLogin} style={s.form}>

            <div style={s.divider}>
              <span style={s.dividerLine} />
              <span style={s.dividerText}>
                {selectedRole ? `${selectedRole.label} credentials` : ""}
              </span>
              <span style={s.dividerLine} />
            </div>

            {/* Username */}
            <div style={s.fieldGroup}>
              <label style={s.label} htmlFor="username">Username</label>
              <div style={s.inputWrapper}>
                <span style={s.inputIcon}>👤</span>
                <input
                  id="username"
                  name="username"
                  type="text"
                  placeholder="Enter username"
                  value={form.username}
                  onChange={handleChange}
                  required
                  style={s.input}
                  autoComplete="username"
                />
              </div>
            </div>

            {/* Password */}
            <div style={s.fieldGroup}>
              <label style={s.label} htmlFor="password">Password</label>
              <div style={s.inputWrapper}>
                <span style={s.inputIcon}>🔒</span>
                <input
                  id="password"
                  name="password"
                  type="password"
                  placeholder="Enter password"
                  value={form.password}
                  onChange={handleChange}
                  required
                  style={s.input}
                  autoComplete="current-password"
                />
              </div>
            </div>

            {error && (
              <div style={s.errorBox}>
                <span>⚠️</span> {error}
              </div>
            )}

            <button
              type="submit"
              disabled={loading}
              style={{ ...s.submitBtn, opacity: loading ? 0.75 : 1 }}
            >
              {loading ? "⟳ Signing in..." : `Sign In as ${selectedRole?.label}`}
            </button>
          </form>
        </div>

        <p style={s.footer}>
          MySQL · <span style={{ color: "#6366f1" }}>Clever Cloud</span> · bz58dt6t4ypdlmtgr532
        </p>
      </div>
    </div>
  );
};

